  "decision_notes": "The problem requires deriving the partition function for a freely jointed chain to find the entropy/internal energy, and then applying the adiabatic constraint to find the force-extension relationship.",
  "helpers": [
    {
      "label": "derivation_agent",
      "instructions": "Derive the partition function and the expression for the entropy S(x, T, n, l) for a freely jointed polymer chain consisting of n segments of length l as a function of end-to-end distance x and temperature T."
    },
    {
      "label": "constraint_agent",
      "instructions": "Given the entropy function S(x, T, n, l), apply the adiabatic constraint (dS = 0) to derive the force-extension relationship F(x) for the polymer chain."
    }
  ],
  "synthesis_brief": "Combine the entropy function derived by the first helper with the adiabatic condition provided by the second helper to produce the final force law F(x)."
}

